INSERT INTO `announcements` (`id`, `title`, `announcement`, `mention_everyone`, `date`, `author_id`, `category`, `is_important`, `is_pinned`) VALUES
(1, 'AtomicShield v1.0b Released!', '<div>We\'re <strong> </strong>excited to announce the release of AtomicShield AntiCheat, a powerful solution <del>designed </del>to ensure fair play and protect gaming communities from cheaters. AtomicShield combines advanced cheat detection, real-time monitoring, and seamless integration, all while maintaining minimal performance impact. This marks a significant step toward creating a more secure and enjoyable gaming experience. Join the movement to keep games fair and competitive with AtomicShield AntiCheat.</div>', 0, '2025-02-25 10:50:24.000000', 1, 'announcement', 0, 1),
(4, '🎉 Welcome to Atomic Shield – Your Free Subscription is Activated! 🚀', '<p>Congratulations! 🎊 You’ve successfully created your account, and your <strong>FREE subscription</strong> is now active. You’re officially part of the <strong>Atomic Shield</strong> community, where <strong>top-tier security meets simplicity.</strong></p><h3><strong>What Happens Next?</strong></h3><div><br></div><ul><li>✅ <strong>Enjoy Full Access</strong>– Your free subscription gives you instant access to our powerful security features.</li><li>✅ <strong>Stay Protected</strong>– Atomic Shield is now working behind the scenes to keep you safe online.</li><li>✅ <strong>Limited-Time Offer</strong>– You got in just in time! This free subscription offer may end at any moment.</li></ul><div><br></div><h3><strong>Spread the Word &amp; Get Rewards!</strong></h3><p>Want to keep your free subscription longer? Invite your friends to sign up and unlock <strong>exclusive perks</strong> for every successful referral!📢 <strong>Don’t Miss Out!</strong> More exciting features and updates are coming soon. Stay connected and enjoy a safer digital experience with Atomic Shield.</p>', 0, '2025-03-25 05:12:03.000000', 1, 'announcement', 0, 0),
(5, 'WE\'RE HIRING RESELLERS – BETA PHASE OPEN!', '<div>Are you interested in working with us and making some real profit? This is your chance!<br><br>- We\'re officially opening up reseller positions, and during this limited beta phase, you\'ll get 100% of the profit from every plan you sell. Yes, 100% – all yours!<br><br>But the beta phase won’t last long, and once it\'s over, this offer disappears.<br>If you’re ready to start, open a ticket on our <a href=\"https://discord.gg/atomic-shield\">discord server</a> now and let’s get you set up.</div>', 0, '2025-04-26 08:49:06.000000', 1, 'announcement', 0, 0),
(6, '﻿ATOMIC SHIELD - THE ULTIMATE PROTECTION FOR YOUR GAMING EXPERIENCE!🚀', '<div>Tired of cheaters ruining your game? <strong><u>Atomic Shield</u></strong> is here to level the playing field! <br>Tested &amp; proven to block the most notorious cheats, including:<br> <br>❌<strong>RedEngine<br> </strong>❌<strong>Susano<br> </strong>❌<strong>Keyser<br> </strong>❌<strong>TZ / TZX<br> </strong>❌<strong>Eulen<br> </strong>❌<strong>Uzui<br> </strong>❌<strong>HxCheats <br>... and many more!</strong> <br> <br>Undetected &amp; Reliable Real-Time Protection Lightweight &amp; Secure Regular Updates Don’t let hackers take over—secure your gameplay with Atomic Shield today!</div><div><br></div>', 1, '2025-06-21 19:35:38.000000', 1, 'announcement', 1, 0);
