(83, '{\"10\": true, \"11\": \"https://discordapp.com/api/webhooks/1402832076310446100/Vg-8ikblIu9VY-fi0qDpOO5oORBo-SR227Ty2851Khd1pS44TWVphDPVEFC4VSAgQLC1\", \"12\": \"\", \"13\": true, \"14\": \"\", \"15\": true, \"16\": \"K\\u1ebft n\\u1ed1i b\\u1ecb ch\\u1eb7n: Agent AtomicShield kh\\u00f4ng ch\\u1ea1y tr\\u00ean h\\u1ec7 th\\u1ed1ng c\\u1ee7a b\\u1ea1n. Vui l\\u00f2ng \\u0111\\u1ea3m b\\u1ea3o agent \\u0111\\u01b0\\u1ee3c c\\u00e0i \\u0111\\u1eb7t \\u0111\\u00fang c\\u00e1ch v\\u00e0 \\u0111ang ho\\u1ea1t \\u0111\\u1ed9ng \\u0111\\u1ec3 tham gia m\\u00e1y ch\\u1ee7. T\\u1ea3i xu\\u1ed1ng t\\u1ea1i \\u0111\\u00e2y: atomic-shield.com\", \"17\": \"B\\u1ea1n \\u0111\\u00e3 b\\u1ecb kick: Agent AtomicShield \\u0111\\u00e3 b\\u1ecb v\\u00f4 hi\\u1ec7u h\\u00f3a \\u0111\\u1ed9t ng\\u1ed9t trong qu\\u00e1 tr\\u00ecnh ch\\u01a1i. Vui l\\u00f2ng kh\\u1edfi \\u0111\\u1ed9ng l\\u1ea1i t\\u00e1c nh\\u00e2n \\u0111\\u1ec3 ti\\u1ebfp t\\u1ee5c ch\\u01a1i.\", \"18\": \"Banned Player\", \"19\": true, \"20\": \"K\\u1ebft n\\u1ed1i c\\u1ee7a b\\u1ea1n d\\u01b0\\u1eddng nh\\u01b0 b\\u1ecb l\\u1ed7i ho\\u1eb7c \\u0111\\u1ecbnh tuy\\u1ebfn sai. \\u0110i\\u1ec1u n\\u00e0y c\\u00f3 th\\u1ec3 do VPN, proxy ho\\u1eb7c c\\u1ea5u h\\u00ecnh m\\u1ea1ng c\\u1ee5c b\\u1ed9. V\\u00ec l\\u00fd do b\\u1ea3o m\\u1eadt, b\\u1ea1n kh\\u00f4ng th\\u1ec3 k\\u1ebft n\\u1ed1i m\\u00e1y ch\\u1ee7 \\u1edf tr\\u1ea1ng th\\u00e1i n\\u00e0y. Vui l\\u00f2ng \\u0111i\\u1ec1u ch\\u1ec9nh k\\u1ebft n\\u1ed1i v\\u00e0 th\\u1eed l\\u1ea1i. N\\u1ebfu b\\u1ea1n cho r\\u1eb1ng \\u0111\\u00e2y l\\u00e0 l\\u1ed7i, h\\u00e3y li\\u00ean h\\u1ec7 v\\u1edbi qu\\u1ea3n tr\\u1ecb vi\\u00ean \\u0111\\u1ec3 \\u0111\\u01b0\\u1ee3c h\\u1ed7 tr\\u1ee3.\"}'),
